builder.Services.AddRateLimiter(limiter =>
{
    // Sliding Window: smooth hơn Fixed Window
    limiter.AddSlidingWindowLimiter("api", opt =>
    {
        opt.PermitLimit = 100;
        opt.Window = TimeSpan.FromMinutes(1);
        opt.SegmentsPerWindow = 6; // check mỗi 10 giây
        opt.QueueLimit = 10;
    });

    // Per-user partitioned limiter
    limiter.AddPolicy("per-user", ctx =>
        RateLimitPartition.GetSlidingWindowLimiter(
            partitionKey: ctx.User.Identity?.Name
                ?? ctx.Connection.RemoteIpAddress?.ToString()
                ?? "anon",
            factory: _ => new SlidingWindowRateLimiterOptions
            {
                PermitLimit = 50, Window = TimeSpan.FromMinutes(1), SegmentsPerWindow = 6
            }));

    // Custom 429 response
    limiter.OnRejected = async (ctx, ct) =>
    {
        ctx.HttpContext.Response.StatusCode = 429;
        if (ctx.Lease.TryGetMetadata(MetadataName.RetryAfter, out var retry))
            ctx.HttpContext.Response.Headers.RetryAfter = retry.TotalSeconds.ToString();
        await ctx.HttpContext.Response.WriteAsJsonAsync(new { error = "Rate limit exceeded" }, ct);
    };
});

app.UseRateLimiter();
app.MapPost("/api/orders", CreateOrder).RequireRateLimiting("per-user");
